/**
 * Vercel Serverless API (hardened)
 *
 * Serves as a health check and live spot-price proxy for the options app.
 * All options data is pre-generated by the GitHub Actions workflow and served
 * as static JSON; this function ONLY provides live spot prices derived from
 * Yahoo Finance futures.
 *
 * Resilience notes
 * ----------------
 * The spot logic is imported LAZILY (dynamic import inside the handler) so a
 * failure in lib/spotPrices (or Yahoo being unreachable) can NEVER bring down
 * the health check or crash the whole function — which previously caused
 * FUNCTION_INVOCATION_FAILED on every endpoint. Every code path returns a
 * valid JSON response.
 *
 * @module api/index
 */

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { fetchSpotPrices } from './spotPrices';

const CORS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

function setCors(res: VercelResponse) {
  for (const [k, v] of Object.entries(CORS)) res.setHeader(k, v);
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  setCors(res);

  // Preflight
  if (req.method === 'OPTIONS') return res.status(204).end();

  if (req.method !== 'GET') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  // ---- Health check (must NEVER fail, even if spot logic is broken) ----
  if (req.query.action !== 'spot') {
    return res.status(200).json({
      status: 'ok',
      service: 'options-wall-analyzer',
      timestamp: new Date().toISOString(),
      dataUrl: '/data/options_data.json',
    });
  }

  // ---- Live spot prices ----
  res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate, max-age=0');
  try {
    const spotData = await fetchSpotPrices();
    return res.status(200).json(spotData);
  } catch (error) {
    // Return a graceful degraded payload so the frontend can fall back rather
    // than receiving a 500 that blocks the whole dashboard.
    return res.status(200).json({
      SPX: null,
      NDX: null,
      SPY: null,
      QQQ: null,
      ES: null,
      NQ: null,
      timestamp: new Date().toISOString(),
      error: 'Spot fetch failed',
      details: String(error),
    });
  }
}
